  ('pages.agences.paris.auto.paragraph.16b4gq', '/agences/paris', 'paragraph', 'Un conseiller vous aide à relire vos éléments de paie, vos frais professionnels et les points à valider avant chaque simulation personnalisée.'),
  ('pages.agences.paris.auto.paragraph.16en81x', '/agences/paris', 'paragraph', 'Vous gardez la main sur votre prospection, votre TJM, votre négociation et votre relation client. The Porters prend le relais sur le cadre contractuel, la facturation, la paie et les démarches administratives liées à votre activité portée.'),
  ('pages.agences.paris.auto.paragraph.17ysdw7', '/agences/paris', 'paragraph', 'The Porters Paris accompagne les consultants indépendants en portage salarial : Product Owners, chefs de projet IT, développeurs, profils data, cloud, cyber et consultants conseil. L''équipe organise des rendez-vous de découverte, des simulations et des cadrages de mission adaptés au marché francilien.'),
  ('pages.agences.paris.auto.paragraph.18ahffj', '/agences/paris', 'paragraph', 'Paris'),
