  ('pages.blog.contrat-portage-salarial.auto.paragraph.1dbhcig', '/blog/contrat-portage-salarial', 'paragraph', 'Le consultant est salarié de la société de portage. Le contrat précise le cadre applicable, les éléments de rémunération et les obligations liées à la mission.'),
  ('pages.blog.contrat-portage-salarial.auto.paragraph.1fandyv', '/blog/contrat-portage-salarial', 'paragraph', 'Contrat de travail, contrat de prestation, convention et responsabilités : comprendre la relation tripartite.'),
  ('pages.blog.contrat-portage-salarial.auto.paragraph.1robbm7', '/blog/contrat-portage-salarial', 'paragraph', 'Partager cet article :'),
  ('pages.blog.contrat-portage-salarial.auto.paragraph.4jz01', '/blog/contrat-portage-salarial', 'paragraph', 'L''entreprise cliente contractualise avec The Porters pour la réalisation de la mission. Le périmètre, la durée, le tarif et les conditions d''exécution doivent être définis clairement.'),
  ('pages.blog.contrat-portage-salarial.auto.paragraph.qrkykr', '/blog/contrat-portage-salarial', 'paragraph', 'Une question ?'),
  ('pages.blog.contrat-portage-salarial.auto.paragraph.t30x3f', '/blog/contrat-portage-salarial', 'paragraph', 'Le portage salarial repose sur plusieurs documents qui encadrent la mission, le statut du consultant et la relation avec l''entreprise cliente.'),
  ('pages.blog.contrat-portage-salarial.auto.paragraph.u2k7no', '/blog/contrat-portage-salarial', 'paragraph', 'Nos conseillers sont à votre disposition pour étudier votre projet et répondre à vos questions sur le portage salarial.'),
