  ('pages.blog.devenir-freelance-informatique.auto.paragraph.1fandyv', '/blog/devenir-freelance-informatique', 'paragraph', 'Passer freelance dans l’IT : autonomie, TJM, missions, statut et intérêt du portage salarial pour démarrer sans structure.'),
  ('pages.blog.devenir-freelance-informatique.auto.paragraph.1robbm7', '/blog/devenir-freelance-informatique', 'paragraph', 'Partager cet article :'),
  ('pages.blog.devenir-freelance-informatique.auto.paragraph.4jz01', '/blog/devenir-freelance-informatique', 'paragraph', 'Le portage salarial peut être une étape utile pour tester le marché, sécuriser la paie et déléguer l''administratif avant de créer une structure.'),
  ('pages.blog.devenir-freelance-informatique.auto.paragraph.qrkykr', '/blog/devenir-freelance-informatique', 'paragraph', 'Une question ?'),
  ('pages.blog.devenir-freelance-informatique.auto.paragraph.t30x3f', '/blog/devenir-freelance-informatique', 'paragraph', 'Devenir freelance informatique attire les développeurs, DevOps, data engineers, architectes cloud et chefs de projet qui veulent choisir leurs missions.'),
  ('pages.blog.devenir-freelance-informatique.auto.paragraph.u2k7no', '/blog/devenir-freelance-informatique', 'paragraph', 'Nos conseillers sont à votre disposition pour étudier votre projet et répondre à vos questions sur le portage salarial.'),
