  ('pages.blog.guide-portage-salarial.auto.paragraph.1dbhcig', '/blog/guide-portage-salarial', 'paragraph', 'Le consultant réalise la mission, l''entreprise cliente achète la prestation, et The Porters porte le contrat de travail, la paie, la facturation et le suivi administratif.'),
  ('pages.blog.guide-portage-salarial.auto.paragraph.1fandyv', '/blog/guide-portage-salarial', 'paragraph', 'Comprendre le portage salarial, la relation tripartite, le contrat de travail et la transformation du chiffre d''affaires en salaire.'),
