  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.heading.g6h7pq', '/blog/portage-salarial-consultant-cybersecurite', 'heading', 'Ce que le portage prend en charge'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.heading.t6gpkw', '/blog/portage-salarial-consultant-cybersecurite', 'heading', 'Questions fréquentes'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.heading.y07sgc', '/blog/portage-salarial-consultant-cybersecurite', 'heading', 'Besoin d''un accompagnement personnalisé ?'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.10fw04y', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Pour appliquer ces principes à votre situation, utilisez le simulateur The Porters ou demandez un rendez-vous avec un conseiller. Les chiffres exacts, les frais et les conditions d''accompagnement sont toujours à valider selon votre mission.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.18ahffj', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Portage salarial pour consultant cybersécurité'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.1dbhcig', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Audit, analyse de risques, gouvernance, SOC, pentest, cloud security ou gestion d’incident impliquent des accès, des livrables et des obligations qui doivent être définis avant le démarrage.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.1fandyv', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'RSSI, GRC, SOC, pentest ou sécurité cloud : comment cadrer une mission cyber en portage salarial sans perdre son autonomie.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.1robbm7', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Partager cet article :'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.1u21qwd', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Le cadre contractuel doit préciser les responsabilités et assurances applicables. Il ne dispense jamais le consultant de respecter les règles de sécurité et le périmètre convenu.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.4jz01', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'La société de portage encadre la relation contractuelle avec le client, la facturation, les déclarations sociales et la paie. Le consultant garde la responsabilité opérationnelle de son intervention.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.f4wvpw', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Oui, lorsque la mission relève d’une prestation intellectuelle autonome et que les conditions d’éligibilité du portage sont réunies.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.qrkykr', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Une question ?'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.t30x3f', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Les consultants cybersécurité interviennent sur des sujets sensibles où le périmètre, les responsabilités et la confidentialité doivent être explicités. Le portage salarial fournit un cadre contractuel et social sans se substituer à l’expertise du consultant.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.u2k7no', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'Nos conseillers sont à votre disposition pour étudier votre projet et répondre à vos questions sur le portage salarial.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.xf7kg6', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', 'TJM, durée, astreintes éventuelles, habilitations, confidentialité, responsabilités, assurance et frais de déplacement doivent apparaître dans les échanges préparatoires.'),
  ('pages.blog.portage-salarial-consultant-cybersecurite.auto.paragraph.z2jwp0', '/blog/portage-salarial-consultant-cybersecurite', 'paragraph', '7 min de lecture'),
