  ('pages.blog.portage-salarial-informatique.auto.paragraph.1dbhcig', '/blog/portage-salarial-informatique', 'paragraph', 'Développeurs, architectes, administrateurs cloud, DevOps, experts cybersécurité, data engineers, consultants ERP, Product Owners et Scrum Masters peuvent y trouver un cadre adapté.'),
  ('pages.blog.portage-salarial-informatique.auto.paragraph.1fandyv', '/blog/portage-salarial-informatique', 'paragraph', 'Le guide dédié aux consultants informatiques qui veulent garder leur autonomie avec une protection salariée.'),
  ('pages.blog.portage-salarial-informatique.auto.paragraph.1robbm7', '/blog/portage-salarial-informatique', 'paragraph', 'Partager cet article :'),
  ('pages.blog.portage-salarial-informatique.auto.paragraph.4jz01', '/blog/portage-salarial-informatique', 'paragraph', 'TJM, frais professionnels, lieu de mission, matériel, rythme de facturation, clause de renouvellement et calendrier de paie doivent être clarifiés dès le départ.'),
  ('pages.blog.portage-salarial-informatique.auto.paragraph.qrkykr', '/blog/portage-salarial-informatique', 'paragraph', 'Une question ?'),
  ('pages.blog.portage-salarial-informatique.auto.paragraph.t30x3f', '/blog/portage-salarial-informatique', 'paragraph', 'Le portage salarial informatique répond aux attentes des consultants tech qui veulent facturer des missions longues ou récurrentes sans gérer seuls toute la structure juridique.'),
  ('pages.blog.portage-salarial-informatique.auto.paragraph.u2k7no', '/blog/portage-salarial-informatique', 'paragraph', 'Nos conseillers sont à votre disposition pour étudier votre projet et répondre à vos questions sur le portage salarial.'),
