  ('pages.blog.role-charge-de-compte-portage-salarial.auto.heading.3g5w6n', '/blog/role-charge-de-compte-portage-salarial', 'heading', 'Passer à l''étape suivante'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.heading.g6h7pq', '/blog/role-charge-de-compte-portage-salarial', 'heading', 'Un soutien sans promesse excessive'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.heading.y07sgc', '/blog/role-charge-de-compte-portage-salarial', 'heading', 'Besoin d''un accompagnement personnalisé ?'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.18ahffj', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'Le rôle du chargé de compte en portage salarial'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.1dbhcig', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'L''objectif est de limiter les ruptures d''information : cadrage administratif, suivi de facturation, lecture des éléments de paie et réponse aux questions pratiques.'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.1fandyv', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'Le chargé de compte est le point d''appui du consultant porté : administratif, facturation, paie, questions de mission et suivi au quotidien.'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.1robbm7', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'Partager cet article :'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.4jz01', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'L''accompagnement peut aider au positionnement et aux bonnes pratiques de prospection, mais il ne doit pas être présenté comme une garantie de missions tant que le client ne l''a pas confirmé.'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.qrkykr', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'Une question ?'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.t30x3f', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'Le chargé de compte donne un visage concret à l''accompagnement. Pour un consultant indépendant, il évite de naviguer seul entre contrats, factures, frais et paie.'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.u2k7no', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'Nos conseillers sont à votre disposition pour étudier votre projet et répondre à vos questions sur le portage salarial.'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.xf7kg6', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', 'Pour appliquer ces principes à votre situation, utilisez le simulateur The Porters ou demandez un rendez-vous avec un conseiller. Les chiffres exacts, les frais et les conditions d''accompagnement sont toujours à valider selon votre mission.'),
  ('pages.blog.role-charge-de-compte-portage-salarial.auto.paragraph.z2jwp0', '/blog/role-charge-de-compte-portage-salarial', 'paragraph', '5 min de lecture'),
