  ('pages.consultants.auto.paragraph.1kao9sa', '/consultants', 'paragraph', 'Ils doivent être liés à l’activité, justifiés et validés selon les règles applicables à votre situation.'),
  ('pages.consultants.auto.paragraph.1kx3w6b', '/consultants', 'paragraph', 'Consultants IT et architecture'),
  ('pages.consultants.auto.paragraph.1n6rins', '/consultants', 'paragraph', 'Vous gardez la main sur votre offre, votre client, votre TJM, votre calendrier et les conditions opérationnelles.'),
  ('pages.consultants.auto.paragraph.1nzigs2', '/consultants', 'paragraph', 'Ce que The Porters gère'),
  ('pages.consultants.auto.paragraph.1rvb5sc', '/consultants', 'paragraph', 'Le chiffre d’affaires disponible finance les frais de gestion applicables, les cotisations, les éventuels frais validés et votre rémunération.'),
  ('pages.consultants.auto.paragraph.4ouu68', '/consultants', 'paragraph', 'Vous restez l’expert en charge de la mission. The Porters intervient sur le cadre contractuel et administratif.'),
  ('pages.consultants.auto.paragraph.bq2yi8', '/consultants', 'paragraph', 'Experts cybersécurité'),
  ('pages.consultants.auto.paragraph.cgk3os', '/consultants', 'paragraph', 'Scrum Masters et Agile Coaches'),
  ('pages.consultants.auto.paragraph.d84s1l', '/consultants', 'paragraph', 'The Porters suit la facturation, les éléments d’activité, les frais validés et le bulletin de salaire.'),
  ('pages.consultants.auto.paragraph.f0xscj', '/consultants', 'paragraph', 'Votre mission, votre expertise et votre TJM restent entre vos mains. Les contrats, la facturation, la paie et le suivi administratif passent entre les nôtres.'),
  ('pages.consultants.auto.paragraph.jwielf', '/consultants', 'paragraph', 'Le résultat est indicatif : TJM, jours facturés, frais, cotisations et conditions contractuelles influencent le net final.'),
