  ('pages.entreprises.auto.paragraph.qrkykr', '/entreprises', 'paragraph', 'Une question ?'),
  ('pages.entreprises.auto.paragraph.vdr63r', '/entreprises', 'paragraph', 'Étudiez le cadre d’une mission internationale avant de valider les conditions contractuelles, sociales et administratives applicables.'),
