  ('pages.expertises.product-project-management.auto.paragraph.dftvvf', '/expertises/product-project-management', 'paragraph', 'Suivre les jalons, les risques, les dépendances et les livrables sans alourdir le projet.'),
  ('pages.expertises.product-project-management.auto.paragraph.f0xscj', '/expertises/product-project-management', 'paragraph', 'Cadrez vos missions de pilotage produit, projet ou programme avec un statut salarié, tout en conservant votre autonomie de conseil et votre relation client.'),
  ('pages.expertises.product-project-management.auto.paragraph.grre9i', '/expertises/product-project-management', 'paragraph', 'Documenter les décisions et organiser le transfert de connaissances pour sécuriser la durée.'),
  ('pages.expertises.product-project-management.auto.paragraph.hbhj9e', '/expertises/product-project-management', 'paragraph', 'Vous pilotez l’expertise et la relation opérationnelle. The Porters porte le cadre salarial, contractuel et administratif.'),
  ('pages.expertises.product-project-management.auto.paragraph.i0qp33', '/expertises/product-project-management', 'paragraph', 'Interlocuteur administratif pendant la mission'),
