  ('pages.livres-blancs.auto.paragraph.ig2r8w', '/livres-blancs', 'paragraph', 'Comparer micro-entreprise, société et portage selon quatre critères : autonomie, protection, gestion administrative et modèle de coûts.'),
  ('pages.livres-blancs.auto.paragraph.pyzpvb', '/livres-blancs', 'paragraph', 'Dites-nous les sujets que vous souhaitez approfondir. Nous vous orienterons vers les ressources disponibles.'),
