  ('pages.qui-sommes-nous.auto.heading.1ia250k', '/qui-sommes-nous', 'heading', 'Votre expertise mérite un cadre à sa hauteur.'),
  ('pages.qui-sommes-nous.auto.heading.1ksmgl7', '/qui-sommes-nous', 'heading', 'Le portage salarial pensé pour les experts du numérique.'),
  ('pages.qui-sommes-nous.auto.heading.1lm5plv', '/qui-sommes-nous', 'heading', 'Un réseau de métiers numériques,'),
