  ('pages.qui-sommes-nous.auto.heading.nussxr', '/qui-sommes-nous', 'heading', 'Un cadre pensé pour les experts IT'),
  ('pages.qui-sommes-nous.auto.heading.uztdz4', '/qui-sommes-nous', 'heading', 'de proximité et de complémentarité.'),
  ('pages.qui-sommes-nous.auto.heading.vts721', '/qui-sommes-nous', 'heading', 'Une histoire de spécialisation,'),
  ('pages.qui-sommes-nous.auto.heading.yyekdd', '/qui-sommes-nous', 'heading', 'Les racines de l’écosystème'),
  ('pages.qui-sommes-nous.auto.paragraph.11saqko', '/qui-sommes-nous', 'paragraph', 'Nous distinguons ce qui est certain, ce qui est estimatif et ce qui doit encore être validé.'),
  ('pages.qui-sommes-nous.auto.paragraph.122bs47', '/qui-sommes-nous', 'paragraph', 'Nous donnons aux consultants l’autonomie pour développer leur activité, avec un cadre salarié clair et un accompagnement qui reste humain.'),
  ('pages.qui-sommes-nous.auto.paragraph.128qswd', '/qui-sommes-nous', 'paragraph', 'Data & IA'),
  ('pages.qui-sommes-nous.auto.paragraph.16iq2tm', '/qui-sommes-nous', 'paragraph', 'Cloud & DevOps'),
  ('pages.qui-sommes-nous.auto.paragraph.184gng5', '/qui-sommes-nous', 'paragraph', 'Considérer le consultant comme un professionnel autonome, pas comme un simple dossier administratif.'),
  ('pages.qui-sommes-nous.auto.paragraph.1dhkhea', '/qui-sommes-nous', 'paragraph', 'Une information utile doit pouvoir être comprise, comparée et vérifiée avant toute décision.'),
  ('pages.qui-sommes-nous.auto.paragraph.1efviim', '/qui-sommes-nous', 'paragraph', 'Conserver un interlocuteur identifiable du premier échange au suivi de la mission.'),
  ('pages.qui-sommes-nous.auto.paragraph.1eqfdjd', '/qui-sommes-nous', 'paragraph', 'La priorité reste la même : une information lisible, un interlocuteur identifiable et un accompagnement adapté à la réalité de chaque mission.'),
  ('pages.qui-sommes-nous.auto.paragraph.1hf1a5v', '/qui-sommes-nous', 'paragraph', 'Expliquer clairement les contrats, la facturation, les frais, la paie et les responsabilités de chacun.'),
  ('pages.qui-sommes-nous.auto.paragraph.1id3tdl', '/qui-sommes-nous', 'paragraph', 'Qui sommes-nous'),
  ('pages.qui-sommes-nous.auto.paragraph.1m2lqrz', '/qui-sommes-nous', 'paragraph', 'Mettre en place un cadre contractuel rigoureux qui reste simple à utiliser au quotidien.'),
  ('pages.qui-sommes-nous.auto.paragraph.1nzigs2', '/qui-sommes-nous', 'paragraph', 'Nos valeurs'),
  ('pages.qui-sommes-nous.auto.paragraph.1p4orls', '/qui-sommes-nous', 'paragraph', 'Organiser l’accompagnement sur place ou à distance selon la mission et les modalités confirmées.'),
  ('pages.qui-sommes-nous.auto.paragraph.1rqskqv', '/qui-sommes-nous', 'paragraph', 'Libre dans la mission.'),
  ('pages.qui-sommes-nous.auto.paragraph.1s0s6fu', '/qui-sommes-nous', 'paragraph', 'Accompagné dans le cadre.'),
  ('pages.qui-sommes-nous.auto.paragraph.1t616ab', '/qui-sommes-nous', 'paragraph', 'L’écosystème se structure autour de deux réponses distinctes : l’expertise ESN portée par KwickStart et le portage salarial proposé par The Porters.'),
  ('pages.qui-sommes-nous.auto.paragraph.1w9wyii', '/qui-sommes-nous', 'paragraph', 'Mission & vision'),
  ('pages.qui-sommes-nous.auto.paragraph.26wfg3', '/qui-sommes-nous', 'paragraph', 'Domaine sélectionné'),
  ('pages.qui-sommes-nous.auto.paragraph.4702ro', '/qui-sommes-nous', 'paragraph', 'Parler le langage des consultants cyber, data, IA, cloud, DevOps, produit, projet et transformation.'),
  ('pages.qui-sommes-nous.auto.paragraph.49m08p', '/qui-sommes-nous', 'paragraph', 'La suite'),
  ('pages.qui-sommes-nous.auto.paragraph.7s1srr', '/qui-sommes-nous', 'paragraph', 'Ensuite'),
  ('pages.qui-sommes-nous.auto.paragraph.bz2og0', '/qui-sommes-nous', 'paragraph', 'RSSI, GRC, SOC, audit'),
  ('pages.qui-sommes-nous.auto.paragraph.im7l07', '/qui-sommes-nous', 'paragraph', 'Un consultant ou une entreprise doit savoir qui contacter et obtenir une réponse liée à sa situation.'),
  ('pages.qui-sommes-nous.auto.paragraph.jjqe5c', '/qui-sommes-nous', 'paragraph', 'Le consultant reste maître de son expertise. The Porters structure le cadre contractuel et administratif.'),
  ('pages.qui-sommes-nous.auto.paragraph.m29l4s', '/qui-sommes-nous', 'paragraph', 'Votre projet'),
  ('pages.qui-sommes-nous.auto.paragraph.m6m0l7', '/qui-sommes-nous', 'paragraph', 'Agilité'),
  ('pages.qui-sommes-nous.auto.paragraph.msrbbw', '/qui-sommes-nous', 'paragraph', 'L’aventure à l’origine du groupe démarre autour de THE BIG PORTERS, avec une ambition : rapprocher les entreprises de talents qualifiés sur leurs projets numériques.'),
  ('pages.qui-sommes-nous.auto.paragraph.omce70', '/qui-sommes-nous', 'paragraph', 'Cybersécurité'),
  ('pages.qui-sommes-nous.auto.paragraph.opxcvt', '/qui-sommes-nous', 'paragraph', 'Nos expertises'),
  ('pages.qui-sommes-nous.auto.paragraph.p2zatl', '/qui-sommes-nous', 'paragraph', 'Nous partons du métier, du niveau de responsabilité et de la réalité de la mission pour proposer un cadre pertinent.'),
