  ('pages.rse.auto.paragraph.1whq3nz', '/rse', 'paragraph', 'Rendre l''information compréhensible, améliorer l''accessibilité du site et traiter chaque candidature ou demande sans discrimination.'),
  ('pages.rse.auto.paragraph.47zzwq', '/rse', 'paragraph', 'Privilégier le travail à distance et les ressources locales lorsque le contexte de mission le permet, afin de limiter les déplacements inutiles.'),
