  ('pages.rse.auto.paragraph.f0xscj', '/rse', 'paragraph', 'Le mémoire technique du Groupe Porters présente des orientations liées au numérique, à l’inclusion, à la proximité et à la transparence. Les indicateurs propres à The Porters seront publiés à mesure de leur validation.'),
  ('pages.rse.auto.paragraph.go8fnn', '/rse', 'paragraph', 'Publier uniquement les indicateurs et certifications officiellement validés.'),
  ('pages.rse.auto.paragraph.h3hdf9', '/rse', 'paragraph', 'Afficher les frais de gestion, expliquer les hypothèses du simulateur et ne publier que des engagements, avis et indicateurs pouvant être justifiés.'),
  ('pages.rse.auto.paragraph.q3qmdo', '/rse', 'paragraph', 'Concevoir des parcours rapides, limiter les médias lourds et privilégier des outils utiles à la mission plutôt que des fonctionnalités superflues.'),
