  ('pages.tarifs.auto.paragraph.f0xscj', '/tarifs', 'paragraph', 'Une simulation utile distingue le chiffre d’affaires, les frais de gestion, les frais professionnels, les cotisations estimatives et le net projeté. Le taux applicable est confirmé selon votre mission.'),
  ('pages.tarifs.auto.paragraph.jo1p7v', '/tarifs', 'paragraph', 'Facturation et suivi administratif de la mission'),
  ('pages.tarifs.auto.paragraph.ko6uzh', '/tarifs', 'paragraph', 'Le niveau de frais et les services inclus dépendent des conditions présentées dans votre simulation et des éléments contractuels validés avant le démarrage.'),
  ('pages.tarifs.auto.paragraph.qrkykr', '/tarifs', 'paragraph', 'Une question ?'),
  ('pages.tarifs.auto.paragraph.qwjkxi', '/tarifs', 'paragraph', 'Le simulateur propose une base de 500 € par mois. Seules les dépenses professionnelles réelles, justifiées et admissibles sont retenues.'),
  ('pages.tarifs.auto.paragraph.rhj6zs', '/tarifs', 'paragraph', 'Le traitement des délais de règlement client et toute éventuelle avance doivent être validés explicitement avant la mission.'),
  ('pages.tarifs.auto.paragraph.sv10tq', '/tarifs', 'paragraph', 'Accès au simulateur et lecture personnalisée du résultat'),
  ('pages.tarifs.auto.paragraph.z69rd8', '/tarifs', 'paragraph', 'Déclarations sociales et documents réglementaires')
) as seed(content_key, route_path, element_type, content)
on conflict (content_key) do update
set route_path = excluded.route_path,
    element_type = excluded.element_type,
    fallback_content = excluded.fallback_content;

insert into public.cms_content_versions (
  content_block_id, version_number, content, format, action
)
select block.id, 1, block.published_content, block.published_format, 'seed'
from public.cms_content_blocks as block
where block.published_version = 1
  and not exists (
    select 1 from public.cms_content_versions as version
    where version.content_block_id = block.id and version.version_number = 1
  );
